/**
 * @summary Get all plan generations
 */
export const getGetAdminGenerationsUrl = (
  params?: GetAdminGenerationsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/generations?${stringifiedParams}`
    : `/api/admin/generations`;
};

export const getAdminGenerations = async (
  params?: GetAdminGenerationsParams,
  options?: RequestInit,
): Promise<AdminGenerationsResponse> => {
  return customFetch<AdminGenerationsResponse>(
    getGetAdminGenerationsUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getGetAdminGenerationsQueryKey = (
  params?: GetAdminGenerationsParams,
) => {
  return [`/api/admin/generations`, ...(params ? [params] : [])] as const;
};

export const getGetAdminGenerationsQueryOptions = <
  TData = Awaited<ReturnType<typeof getAdminGenerations>>,
  TError = ErrorType<void>,
>(
  params?: GetAdminGenerationsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAdminGenerations>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetAdminGenerationsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getAdminGenerations>>
  > = ({ signal }) =>
    getAdminGenerations(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getAdminGenerations>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

